parameters.jsCode:
const item = $input.first();
const emailBody = item.json.email_body || '';
const subject = item.json.subject || '';
let attachmentText = '';
const binaryKeys = Object.keys(item.binary || {});
for (const key of binaryKeys) {
  const binary = item.binary[key];
  if (binary.mimeType === 'application/pdf' || binary.fileName?.endsWith('.pdf') || binary.mimeType?.includes('document')) {
    attachmentText += `\n[Attachment: ${binary.fileName}]`;
  }
}
const dealText = [`Subject: ${subject}`, `From: ${item.json.sender_name} <${item.json.sender_email}>`, '', 'Email Content:', emailBody, attachmentText ? '\nAttachments detected: ' + attachmentText : ''].filter(Boolean).join('\n');
return [{ json: { ...item.json, deal_text: dealText, deal_text_length: dealText.length } }];

